class Solution {
public:
    vector<int> smallestTrimmedNumbers(vector<string>& nums, vector<vector<int>>& queries) {
        int n = nums.size(), m = nums[0].size();
        vector<vector<pair<string, int>>> buckets(m + 1);

        for (int i = 0; i < n; ++i) {
            for (int j = 1; j <= m; ++j) {
                buckets[j].emplace_back(nums[i].substr(m - j), i);
            }
        }

        for (auto& b : buckets) {
            sort(b.begin(), b.end());
        }

        vector<int> ans;
        for (auto& q : queries) {
            int k = q[0], trim = q[1];
            ans.push_back(buckets[trim][k - 1].second);
        }

        return ans;
    }
};
